#include <stdio.h>
#include <stdlib.h>

int main()
{
    int counter=-1,help=-1, last=-1, check=0, hello=0;
    char str[101];
    scanf("%s",str);
    for(int i=0; i<strlen(str); i++)
    {
        if(str[i]=='A' || str[i]=='E' || str[i]=='I' || str[i]=='O' || str[i]=='U' || str[i]=='Y')
        {
            help=i;
            if(help-counter > last)
             {
                 last=help-counter; counter=i;

             }
             else counter=i;
            check++; hello=i;
        }
         else if(i==strlen(str)-1 && (strlen(str)+1)-counter>last)
            {last=strlen(str)+-counter;}
    }
    if(check==1 && last<2) printf("%d", (strlen(str)-hello));
    else if(last==-1) printf("%d", strlen(str)+1);
    else printf("%d", last);
    return 0;
}

