use std::cmp::{max,min};
#[allow(unused_imports)]
use std::collections::{HashMap,HashSet,VecDeque};

#[allow(unused_macros)]
macro_rules! readln {
    () => {{
        use std::io;

        let mut buf = String::new();
        io::stdin().read_line(&mut buf).unwrap();
        buf.trim().to_string()
    }};
    ( $t:ty ) => {{
        let input = readln!();
        input.parse::<$t>().unwrap()
    }};
    ( $( $t:ty ),+ ) => {{
        let input = readln!();
        let mut input = input.split_whitespace();
        (
            $(
                input.next().unwrap().parse::<$t>().unwrap(),
            )+
        )
    }}
}

#[allow(unused_macros)]
macro_rules! readvec {
    ( $t:ty ) => {{
        let input = readln!();
        let mut input = input.split_whitespace();
        let mut result = Vec::new();
        for elem in input {
            result.push(elem.parse::<$t>().unwrap());
        }
        result
    }}
}

fn main() {
    let mut s = String::from("A");
    s += readln!().as_ref();
    s += "A";
    let v : Vec<usize> = s.chars().enumerate().filter(|&(i,c)|c=='A' || c=='E' || c=='I' || c=='O' || c=='U' || c=='Y').map(|(i,c)|i).collect();
    let u : usize = v.iter().skip(1).zip(v.iter()).map(|(i,j)|i-j).max().unwrap();
    println!("{}",u);
}
